unit lipdecide;

interface

uses
  globals;

procedure DECIDE;
function REALCOMPARE(A, B: real): COMPTYPE;

implementation

{ REALCOMPARE compares two real numbers with six significant digit precision }
function REALCOMPARE(A, B: real): COMPTYPE;
const
  EPSILON = 1E-6;
var
  diff: real;
begin
  diff := A - B;
  if abs(diff) < EPSILON then
    REALCOMPARE := EQ
  else if diff < 0 then
    REALCOMPARE := LT
  else
    REALCOMPARE := GT;
end;

{ Calculate distance between two points }
function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := sqrt((x2 - x1) * (x2 - x1) + (y2 - y1) * (y2 - y1));
end;

{ Check if three points fit in a circle of given radius }
function FitsInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  d12, d13, d23: real;
  ax, ay, bx, by: real;
  d: real;
  cx, cy: real;
  dist: real;
begin
  d12 := Distance(x1, y1, x2, y2);
  d13 := Distance(x1, y1, x3, y3);
  d23 := Distance(x2, y2, x3, y3);

  { Check if triangle is degenerate }
  if REALCOMPARE(d12, 0) = EQ then
  begin
    dist := Distance(x1, y1, x3, y3);
    FitsInCircle := REALCOMPARE(dist, 2 * radius) <= EQ;
    exit;
  end;

  if REALCOMPARE(d13, 0) = EQ then
  begin
    dist := Distance(x1, y1, x2, y2);
    FitsInCircle := REALCOMPARE(dist, 2 * radius) <= EQ;
    exit;
  end;

  if REALCOMPARE(d23, 0) = EQ then
  begin
    dist := Distance(x2, y2, x1, y1);
    FitsInCircle := REALCOMPARE(dist, 2 * radius) <= EQ;
    exit;
  end;

  { Compute circumradius using formula: R = (abc)/(4K) where K is area }
  ax := x2 - x1;
  ay := y2 - y1;
  bx := x3 - x1;
  by := y3 - y1;
  d := ax * by - ay * bx;

  if abs(d) < 1E-10 then
  begin
    { Collinear points: radius is half the longest side }
    if REALCOMPARE(d12, d13) >= EQ then
      dist := d12
    else
      dist := d13;
    if REALCOMPARE(d23, dist) > EQ then
      dist := d23;
    FitsInCircle := REALCOMPARE(dist, 2 * radius) <= EQ;
  end
  else
  begin
    d := 2 * d;
    cx := ((x1 + x2) * (x2 - x1) + (y1 + y2) * (y2 - y1)) / d * by -
          ((x1 + x3) * (x3 - x1) + (y1 + y3) * (y3 - y1)) / d * ay;
    cy := ((x1 + x3) * (x3 - x1) + (y1 + y3) * (y3 - y1)) / d * ax -
          ((x1 + x2) * (x2 - x1) + (y1 + y2) * (y2 - y1)) / d * bx;

    dist := Distance(x1, y1, cx, cy);
    FitsInCircle := REALCOMPARE(dist, radius) <= EQ;
  end;
end;

{ Calculate angle between three points in radians }
function ComputeAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  v1x, v1y, v2x, v2y: real;
  dot, cross: real;
begin
  v1x := x1 - x2;
  v1y := y1 - y2;
  v2x := x3 - x2;
  v2y := y3 - y2;

  dot := v1x * v2x + v1y * v2y;
  cross := v1x * v2y - v1y * v2x;

  ComputeAngle := arctan2(cross, dot);
  if ComputeAngle < 0 then
    ComputeAngle := ComputeAngle + 2 * PI;
end;

{ Calculate area of triangle }
function ComputeArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  ComputeArea := abs((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2);
end;

{ Get quadrant for a point }
function GetQuadrant(x, y: real): integer;
begin
  if REALCOMPARE(x, 0) >= EQ then
  begin
    if REALCOMPARE(y, 0) >= EQ then
      GetQuadrant := 1  { Quadrant I }
    else
      GetQuadrant := 3  { Quadrant III }
  end
  else
  begin
    if REALCOMPARE(y, 0) > EQ then
      GetQuadrant := 2  { Quadrant II }
    else
      GetQuadrant := 3  { Quadrant III }
  end;
end;

{ Distance from point to line }
function DistancePointToLine(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy, num, denom: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  denom := sqrt(dx * dx + dy * dy);

  if REALCOMPARE(denom, 0) = EQ then
    DistancePointToLine := Distance(px, py, x1, y1)
  else
  begin
    num := abs((y2 - y1) * px - (x2 - x1) * py + x2 * y1 - y2 * x1);
    DistancePointToLine := num / denom;
  end;
end;

{ Main DECIDE procedure }
procedure DECIDE;
var
  i, j, k: integer;
  quad_count: integer;
  quads: set of integer;
  dist, area: real;
  angle: real;
  cond1, cond2: boolean;
begin
  { Initialize all CMV entries to false }
  for i := 1 to 15 do
    CMV[i] := false;

  { LIC 1: Two consecutive points distance > LENGTH1 apart }
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(Distance(X[i], Y[i], X[i+1], Y[i+1]), PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      break;
    end;
  end;

  { LIC 2: Three consecutive points cannot fit in circle of radius RADIUS1 }
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not FitsInCircle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2], PARAMETERS.RADIUS1) then
    begin
      CMV[2] := true;
      break;
    end;
  end;

  { LIC 3: Three consecutive points form angle outside (PI - EPSILON, PI + EPSILON) }
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if (REALCOMPARE(X[i], X[i+1]) <> EQ) or (REALCOMPARE(Y[i], Y[i+1]) <> EQ) then
    begin
      if (REALCOMPARE(X[i+2], X[i+1]) <> EQ) or (REALCOMPARE(Y[i+2], Y[i+1]) <> EQ) then
      begin
        angle := ComputeAngle(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
        if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
           (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
        begin
          CMV[3] := true;
          break;
        end;
      end;
    end;
  end;

  { LIC 4: Three consecutive points form triangle with area > AREA1 }
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := ComputeArea(X[i], Y[i], X[i+1], Y[i+1], X[i+2], Y[i+2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      break;
    end;
  end;

  { LIC 5: Q_PTS consecutive points in > QUADS quadrants }
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quads := [];
    for j := i to i + PARAMETERS.Q_PTS - 1 do
      include(quads, GetQuadrant(X[j], Y[j]));
    if cardinal(quads) > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      break;
    end;
  end;

  { LIC 6: Two consecutive points with X[j] - X[i] < 0 }
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i+1] - X[i], 0) = LT then
    begin
      CMV[6] := true;
      break;
    end;
  end;

  { LIC 7: N_PTS consecutive points with at least one > DIST from line }
  CMV[7] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
    begin
      for j := i + 1 to i + PARAMETERS.N_PTS - 1 do
      begin
        dist := DistancePointToLine(X[j], Y[j], X[i], Y[i], X[i + PARAMETERS.N_PTS - 1], Y[i + PARAMETERS.N_PTS - 1]);
        if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
        begin
          CMV[7] := true;
          break;
        end;
      end;
      if CMV[7] then break;
    end;
  end;

  { LIC 8: Two points separated by K_PTS intervening, distance > LENGTH1 }
  CMV[8] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      if REALCOMPARE(Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]),
                     PARAMETERS.LENGTH1) = GT then
      begin
        CMV[8] := true;
        break;
      end;
    end;
  end;

  { LIC 9: Three points separated by A_PTS and B_PTS, cannot fit circle RADIUS1 }
  CMV[9] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      if not FitsInCircle(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                          X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                          PARAMETERS.RADIUS1) then
      begin
        CMV[9] := true;
        break;
      end;
    end;
  end;

  { LIC 10: Three points separated by C_PTS and D_PTS, angle outside (PI-EPSILON, PI+EPSILON) }
  CMV[10] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
    begin
      if (REALCOMPARE(X[i], X[i + PARAMETERS.C_PTS + 1]) <> EQ) or
         (REALCOMPARE(Y[i], Y[i + PARAMETERS.C_PTS + 1]) <> EQ) then
      begin
        if (REALCOMPARE(X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2], X[i + PARAMETERS.C_PTS + 1]) <> EQ) or
           (REALCOMPARE(Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2], Y[i + PARAMETERS.C_PTS + 1]) <> EQ) then
        begin
          angle := ComputeAngle(X[i], Y[i], X[i + PARAMETERS.C_PTS + 1], Y[i + PARAMETERS.C_PTS + 1],
                                X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2], Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2]);
          if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
             (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
          begin
            CMV[10] := true;
            break;
          end;
        end;
      end;
    end;
  end;

  { LIC 11: Three points separated by E_PTS and F_PTS, area > AREA1 }
  CMV[11] := false;
  if NUMPOINTS >= 5 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      area := ComputeArea(X[i], Y[i], X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
                          X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      begin
        CMV[11] := true;
        break;
      end;
    end;
  end;

  { LIC 12: Two points separated by G_PTS intervening with X[j] - X[i] < 0 }
  CMV[12] := false;
  if NUMPOINTS >= 3 then
  begin
    for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
    begin
      if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0) = LT then
      begin
        CMV[12] := true;
        break;
      end;
    end;
  end;

  { LIC 13: Two conditions on K_PTS separated points (distance > LENGTH1 and < LENGTH2) }
  CMV[13] := false;
  if NUMPOINTS >= 3 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
    begin
      dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
      if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
        cond1 := true;
      if REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT then
        cond2 := true;
    end;
    CMV[13] := cond1 and cond2;
  end;

  { LIC 14: Radius1 and Radius2 conditions on A_PTS/B_PTS separated points }
  CMV[14] := false;
  if NUMPOINTS >= 5 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
    begin
      if not FitsInCircle(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                          X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                          PARAMETERS.RADIUS1) then
        cond1 := true;
      if FitsInCircle(X[i], Y[i], X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
                      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
                      PARAMETERS.RADIUS2) then
        cond2 := true;
    end;
    CMV[14] := cond1 and cond2;
  end;

  { LIC 15: Area1 and Area2 conditions on E_PTS/F_PTS separated points }
  CMV[15] := false;
  if NUMPOINTS >= 5 then
  begin
    cond1 := false;
    cond2 := false;
    for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
    begin
      area := ComputeArea(X[i], Y[i], X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
                          X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);
      if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
        cond1 := true;
      if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
        cond2 := true;
    end;
    CMV[15] := cond1 and cond2;
  end;

  { Compute PUM off-diagonal elements }
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i <> j then
      begin
        case LCM[i, j] of
          NOTUSED: PUM[i, j] := true;
          ANDD: PUM[i, j] := CMV[i] and CMV[j];
          ORR: PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;
  end;

  { Compute FUV }
  for i := 1 to 15 do
  begin
    FUV[i] := not PUM[i, i];
    if not FUV[i] then
    begin
      FUV[i] := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          FUV[i] := false;
          break;
        end;
      end;
    end;
  end;

  { Compute final LAUNCH decision }
  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      break;
    end;
  end;
end;

end.
